func (g *queryGenerator) appendCleanUpdateByQuery(
	indexKey string,
	updateByQueries []*repository.QueryRequest[repository.Params],
	queryModel *repository.QueryModel,
	executeSequenceOnNoMatchOrUpdate bool,
) {
	for _, updateByQuery := range updateByQueries {
		if updateByQuery == nil {
			continue
		}

		queryModel.CleanUpdateByQuery = append(
			queryModel.CleanUpdateByQuery,
			&repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
				ExecuteSequenceOnMatchButNoUpdate: executeSequenceOnNoMatchOrUpdate,
				Indices:                           []string{indexKey},
				Body:                              updateByQuery,
				LogContext:                        updateByQuery.LogContext,
			},
		)

		queryModel.CleanUpIndices.Add(indexKey)
		queryModel.AllIndices.Add(indexKey)
	}
}

