Can you give me some ideas on how to design a migration framework that defines a contract for migration operations? Allow devs to add new migration operations. and then executes them after the DB publish code. (shown below is the DB publish code)

```go gumdrop/cmd/opensearch-mgmt/startup/startup.go:25-82
// Excerpt from: 
func Publish(
	logContext *log.Context,
	opensearchClient repository.NoSqlMgmtRepository,
	consulClient consul.Client,
	sleepUntilTerminated bool,
	rootDir string,
) {
	// Set so that health check comes back healthy
	applicationInfo.SetPublishFinished(true, true)
	processHaltChannel, err := publish(logContext, opensearchClient, consulClient, rootDir)
	if err != nil {
		failTheHealthCheck(logContext, err)
	} else if processHaltChannel == nil {
		log.Infow(logContext, "Gathering aliases complete.")
	} else if err = <-processHaltChannel; err != nil {
		failTheHealthCheck(logContext, err)
	} else {
		log.Infow(logContext, "Publish complete.")
	}

	log.Flush()

	if sleepUntilTerminated && processHaltChannel != nil {
		<-processHaltChannel
	}
}

func publish(
	logContext *log.Context,
	noSqlMgmtRepository repository.NoSqlMgmtRepository,
	consulClient consul.Client,
	scriptRootDir string,
) (actionChanel <-chan error, err error) {
	return consulClient.RunOnceAction(
		logContext,
		publishSyncKey,
		func() error {
			published, err := opensearchInternal.PublishIndices(
				logContext,
				noSqlMgmtRepository,
			)
			if err != nil {
				return err
			} else if published {
				templatedScriptsDirPath := path.Join(scriptRootDir, opensearchInternal.TemplatedScriptsRootDirName)
				opensearchInternal.PublishTemplatedScripts(logContext, noSqlMgmtRepository, templatedScriptsDirPath)
			}

			return nil
		},
		func() error {
			opensearchInternal.CheckPublished(logContext, noSqlMgmtRepository)

			return nil
		},
	)
}

