# Data Migration Framework Design Ideas

Based on your codebase structure and needs, here's a design for a migration framework that you could implement after the DB publish code:

## 1. Migration Interface

Start by defining a clear interface for migrations:

```go
// Migration defines the contract for database migrations
type Migration interface {
    // ID returns a unique identifier for the migration
    ID() string

    // Version returns the version number of the migration
    Version() string

    // Description returns a human-readable description of what the migration does
    Description() string

    // Execute performs the migration
    Execute(ctx *log.Context, client repository.NoSqlRepository) error
}
```

## 2. Migration Registry

Create a registry to keep track of available migrations:

```go
type MigrationRegistry struct {
    migrations []Migration
    mutex      sync.RWMutex
}

func NewMigrationRegistry() *MigrationRegistry {
    return &MigrationRegistry{
        migrations: make([]Migration, 0),
    }
}

func (r *MigrationRegistry) Register(migration Migration) {
    r.mutex.Lock()
    defer r.mutex.Unlock()
    r.migrations = append(r.migrations, migration)
}

func (r *MigrationRegistry) GetMigrations() []Migration {
    r.mutex.RLock()
    defer r.mutex.RUnlock()
    result := make([]Migration, len(r.migrations))
    copy(result, r.migrations)
    return result
}
```

## 3. Migration Runner

Create a migration runner that handles execution:

```go
type MigrationRunner struct {
    registry         *MigrationRegistry
    opensearchClient repository.NoSqlRepository
    schemaMapper     schemaMapping.SchemaMapper
    executedPath     string // Path to the JSON file tracking executed migrations
}

func NewMigrationRunner(
    registry *MigrationRegistry,
    client repository.NoSqlRepository,
    schemaMapper schemaMapping.SchemaMapper,
    executedPath string,
) *MigrationRunner {
    return &MigrationRunner{
        registry:         registry,
        opensearchClient: client,
        schemaMapper:     schemaMapper,
        executedPath:     executedPath,
    }
}

func (r *MigrationRunner) Run(logContext *log.Context) error {
    // Load executed migrations
    executed, err := r.loadExecutedMigrations()
    if err != nil {
        return errors.Wrap(err, "failed to load executed migrations")
    }

    // Get all registered migrations
    migrations := r.registry.GetMigrations()

    // Sort migrations by version
    sort.Slice(migrations, func(i, j int) bool {
        return semver.Compare(migrations[i].Version(), migrations[j].Version()) < 0
    })

    // Execute migrations that haven't been run yet
    for _, migration := range migrations {
        id := migration.ID()
        if _, ok := executed[id]; !ok {
            log.Infow(logContext, "Executing migration", "id", id, "version", migration.Version(), "description", migration.Description())

            if err := migration.Execute(logContext, r.opensearchClient); err != nil {
                return errors.Wrapf(err, "failed to execute migration %s", id)
            }

            // Record successful migration
            executed[id] = ExecutedMigration{
                ID:          id,
                Version:     migration.Version(),
                Description: migration.Description(),
                ExecutedAt:  time.Now().UTC(),
            }

            if err := r.saveExecutedMigrations(executed); err != nil {
                return errors.Wrap(err, "failed to save executed migrations")
            }

            log.Infow(logContext, "Migration executed successfully", "id", id)
        }
    }

    return nil
}

type ExecutedMigration struct {
    ID          string    `json:"id"`
    Version     string    `json:"version"`
    Description string    `json:"description"`
    ExecutedAt  time.Time `json:"executed_at"`
}

func (r *MigrationRunner) loadExecutedMigrations() (map[string]ExecutedMigration, error) {
    executed := make(map[string]ExecutedMigration)

    if _, err := os.Stat(r.executedPath); os.IsNotExist(err) {
        return executed, nil
    }

    data, err := os.ReadFile(r.executedPath)
    if err != nil {
        return nil, err
    }

    if err := json.Unmarshal(data, &executed); err != nil {
        return nil, err
    }

    return executed, nil
}

func (r *MigrationRunner) saveExecutedMigrations(executed map[string]ExecutedMigration) error {
    data, err := json.MarshalIndent(executed, "", "  ")
    if err != nil {
        return err
    }

    return os.WriteFile(r.executedPath, data, 0644)
}
```

## 4. Base Migration Type

Provide a base implementation that makes it easy to create new migrations:

```go
type BaseMigration struct {
    id          string
    version     string
    description string
}

func NewBaseMigration(id, version, description string) BaseMigration {
    return BaseMigration{
        id:          id,
        version:     version,
        description: description,
    }
}

func (m BaseMigration) ID() string {
    return m.id
}

func (m BaseMigration) Version() string {
    return m.version
}

func (m BaseMigration) Description() string {
    return m.description
}
```

## 5. Example Implementation of a Migration

Here's how developers would create a specific migration:

```go
type DeleteOldDocumentsMigration struct {
    BaseMigration
}

func NewDeleteOldDocumentsMigration() Migration {
    return &DeleteOldDocumentsMigration{
        BaseMigration: NewBaseMigration(
            "delete-old-documents-001",
            "1.0.0",
            "Delete documents older than 1 year",
        ),
    }
}

func (m *DeleteOldDocumentsMigration) Execute(logContext *log.Context, client repository.NoSqlRepository) error {
    // Create filter for documents older than 1 year
    oneYearAgo := time.Now().AddDate(-1, 0, 0).Format(time.RFC3339)

    // Create query request
    filters := []repository.Filter{
        {
            Field: "timestamp",
            Op:    "lt",
            Value: oneYearAgo,
        },
    }

    deleteByQueries, err := repository.NewShouldQueryRequest(
        logContext,
        nil,
        "",
        nil,
        filters,
        nil,
    )
    if err != nil {
        return errors.Wrap(err, "failed to create delete query")
    }

    // Execute delete by query
    for _, deleteByQuery := range deleteByQueries {
        queryDetails := &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
            Indices:    []string{"your-index-name"},
            Body:       deleteByQuery,
            LogContext: logContext,
        }

        _, err = client.DeleteByQuery(queryDetails)
        if err != nil {
            return errors.Wrap(err, "failed to execute delete by query")
        }
    }

    return nil
}
```

## 6. Integration with DB Publish Process

Modify your `Publish` function to run migrations after publishing:

```go
func publish(
    logContext *log.Context,
    noSqlMgmtRepository repository.NoSqlMgmtRepository,
    consulClient consul.Client,
    scriptRootDir string,
) (actionChanel <-chan error, err error) {
    return consulClient.RunOnceAction(
        logContext,
        publishSyncKey,
        func() error {
            published, err := opensearchInternal.PublishIndices(
                logContext,
                noSqlMgmtRepository,
            )
            if err != nil {
                return err
            } else if published {
                templatedScriptsDirPath := path.Join(scriptRootDir, opensearchInternal.TemplatedScriptsRootDirName)
                opensearchInternal.PublishTemplatedScripts(logContext, noSqlMgmtRepository, templatedScriptsDirPath)

                // Run migrations after successfully publishing
                if err := runMigrations(logContext, noSqlMgmtRepository); err != nil {
                    return errors.Wrap(err, "failed to run migrations")
                }
            }

            return nil
        },
        func() error {
            opensearchInternal.CheckPublished(logContext, noSqlMgmtRepository)

            return nil
        },
    )
}

func runMigrations(logContext *log.Context, repository repository.NoSqlMgmtRepository) error {
    // Create migration registry and register migrations
    registry := NewMigrationRegistry()

    // Register all migrations
    registry.Register(NewDeleteOldDocumentsMigration())
    // Add more migrations here...

    // Create and run migration runner
    runner := NewMigrationRunner(
        registry,
        repository,
        schemaMapper,
        "/path/to/executed-migrations.json",
    )

    return runner.Run(logContext)
}
```

This design provides:
1. A clean interface for defining migrations
2. A registry for registering available migrations
3. A runner that handles execution order and tracking
4. A base implementation to simplify creating new migrations
5. Integration with your existing DB publish process

Developers can easily add new migrations by implementing the `Migration` interface and registering them with the registry.
looks good to me, but is there a way to automatically discover and register migrations? Maybe we could also utilize code generation to simplify the process.
# Enhanced Migration Framework with Auto-Discovery and Code Generation

You're absolutely right. We can significantly improve the developer experience by implementing auto-discovery of migrations and adding code generation to streamline the process. Here's how we can enhance the design:

## 1. Auto-Discovery of Migrations

We can implement auto-discovery using Go's package initialization pattern and a global registry:

```go
// In a new file: migration/registry.go
package migration

import (
	"sync"
)

var (
	// globalRegistry is the shared registry for all migrations
	globalRegistry = NewRegistry()
)

// Registry keeps track of all registered migrations
type Registry struct {
	migrations []Migration
	mutex      sync.RWMutex
}

// NewRegistry creates a new migration registry
func NewRegistry() *Registry {
	return &Registry{
		migrations: make([]Migration, 0),
	}
}

// Register adds a migration to the registry
func (r *Registry) Register(migration Migration) {
	r.mutex.Lock()
	defer r.mutex.Unlock()
	r.migrations = append(r.migrations, migration)
}

// GetMigrations returns all registered migrations
func (r *Registry) GetMigrations() []Migration {
	r.mutex.RLock()
	defer r.mutex.RUnlock()
	result := make([]Migration, len(r.migrations))
	copy(result, r.migrations)
	return result
}

// Register adds a migration to the global registry
func Register(migration Migration) {
	globalRegistry.Register(migration)
}

// GetRegisteredMigrations returns all migrations from the global registry
func GetRegisteredMigrations() []Migration {
	return globalRegistry.GetMigrations()
}
```

## 2. Code Generation for Migrations

We can create a Go generate tool that scans a directory for migration templates and generates actual migration code. Here's how it might work:

### First, create a code generator tool:

```go
// cmd/generate-migrations/main.go
package main

import (
	"bytes"
	"flag"
	"fmt"
	"go/format"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"text/template"
	"time"
)

var (
	srcDir     = flag.String("src", "migrations/templates", "Directory containing migration templates")
	outputDir  = flag.String("out", "migrations/generated", "Directory where generated migrations will be placed")
	packageName = flag.String("pkg", "migrations", "Package name for generated migrations")
)

func main() {
	flag.Parse()

	// Ensure the output directory exists
	if err := os.MkdirAll(*outputDir, 0755); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create output directory: %v\n", err)
		os.Exit(1)
	}

	// Find all template files
	templateFiles, err := filepath.Glob(filepath.Join(*srcDir, "*.go.tmpl"))
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to find template files: %v\n", err)
		os.Exit(1)
	}

	for _, templateFile := range templateFiles {
		if err := processTemplate(templateFile); err != nil {
			fmt.Fprintf(os.Stderr, "Failed to process %s: %v\n", templateFile, err)
			os.Exit(1)
		}
	}
}

func processTemplate(templateFile string) error {
	// Read template file
	content, err := os.ReadFile(templateFile)
	if err != nil {
		return fmt.Errorf("failed to read template file: %w", err)
	}

	// Extract migration details from template
	baseName := filepath.Base(templateFile)
	nameWithoutExt := strings.TrimSuffix(baseName, ".go.tmpl")

	re := regexp.MustCompile(`^([a-zA-Z0-9]+)_v([0-9]+\.[0-9]+\.[0-9]+)_(.+)$`)
	matches := re.FindStringSubmatch(nameWithoutExt)
	if len(matches) != 4 {
		return fmt.Errorf("template filename does not match expected pattern: %s", baseName)
	}

	id := matches[1]
	version := matches[2]
	description := strings.ReplaceAll(matches[3], "_", " ")

	tmpl, err := template.New("migration").Parse(string(content))
	if err != nil {
		return fmt.Errorf("failed to parse template: %w", err)
	}

	var buf bytes.Buffer
	err = tmpl.Execute(&buf, map[string]interface{}{
		"ID":          id,
		"Version":     version,
		"Description": description,
		"Package":     *packageName,
		"Generated":   time.Now().Format(time.RFC3339),
	})
	if err != nil {
		return fmt.Errorf("failed to execute template: %w", err)
	}

	// Format the generated Go code
	formattedCode, err := format.Source(buf.Bytes())
	if err != nil {
		return fmt.Errorf("failed to format generated code: %w", err)
	}

	// Write the formatted code to the output file
	outputFile := filepath.Join(*outputDir, nameWithoutExt+".go")
	if err := os.WriteFile(outputFile, formattedCode, 0644); err != nil {
		return fmt.Errorf("failed to write output file: %w", err)
	}

	fmt.Printf("Generated migration: %s\n", outputFile)
	return nil
}
```

