import (
	"time"

	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/migration"
	"gumdrop/internal/pkg/repository"
	"github.com/pkg/errors"
)

// DeleteOldDocumentsMigration implements a migration that removes old documents
type DeleteOldDocumentsMigration struct {
	migration.BaseMigration
}

// Execute performs the migration
func (m *DeleteOldDocumentsMigration) Execute(logContext *log.Context, client repository.NoSqlRepository) error {
	// Create filter for documents older than 1 year
	oneYearAgo := time.Now().AddDate(-1, 0, 0).Format(time.RFC3339)

	// Create query request
	filters := []repository.Filter{
		{
			Field: "timestamp",
			Op:    "lt",
			Value: oneYearAgo,
		},
	}

	deleteByQueries, err := repository.NewShouldQueryRequest(
		logContext,
		nil,
		"",
		nil,
		filters,
		nil,
	)
	if err != nil {
		return errors.Wrap(err, "failed to create delete query")
	}

	// Execute delete by query
	for _, deleteByQuery := range deleteByQueries {
		queryDetails := &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
			Indices:    []string{"your-index-name"},
			Body:       deleteByQuery,
			LogContext: logContext,
		}

		_, err = client.DeleteByQuery(queryDetails)
		if err != nil {
			return errors.Wrap(err, "failed to execute delete by query")
		}
	}

	return nil
}
```

## 3. Migration Factory

Create a factory that constructs migration instances based on the implementation name from YAML:

```go
// migration/factory.go
package migration

import (
	"fmt"
	"reflect"
)

var implementationRegistry = make(map[string]reflect.Type)

// RegisterImplementation registers a migration implementation with the factory
func RegisterImplementation(name string, implementation Migration) {
	implementationRegistry[name] = reflect.TypeOf(implementation).Elem()
}

// CreateMigration creates a migration instance based on the implementation name
func CreateMigration(implementation string, id string, version string, description string) (Migration, error) {
	implementationType, ok := implementationRegistry[implementation]
	if !ok {
		return nil, fmt.Errorf("unknown migration implementation: %s", implementation)
	}

	// Create new instance of the implementation
	instance := reflect.New(implementationType).Interface().(Migration)

	// Initialize with base migration data
	if baseSetter, ok := instance.(interface{ SetBaseMigration(BaseMigration) }); ok {
		baseSetter.SetBaseMigration(NewBaseMigration(id, version, description))
	}

	return instance, nil
}
