## 5. YAML Manifest Loader

Create a loader that reads all YAML manifests:

```go
// migration/manifest.go
package migration

import (
	"io/fs"
	"os"
	"path/filepath"

	"gopkg.in/yaml.v3"
)

// MigrationManifest represents a YAML migration definition
type MigrationManifest struct {
	ID            string `yaml:"id"`
	Version       string `yaml:"version"`
	Description   string `yaml:"description"`
	Implementation string `yaml:"implementation"`
}

// LoadManifests loads all migration manifests from a directory
func LoadManifests(manifestDir string) ([]MigrationManifest, error) {
	var manifests []MigrationManifest

	err := filepath.WalkDir(manifestDir, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}

		// Skip directories and non-YAML files
		if d.IsDir() || filepath.Ext(path) != ".yaml" && filepath.Ext(path) != ".yml" {
			return nil
		}

		// Read and parse the YAML file
		data, err := os.ReadFile(path)
		if err != nil {
			return err
		}

		var manifest MigrationManifest
		if err := yaml.Unmarshal(data, &manifest); err != nil {
			return err
		}

		manifests = append(manifests, manifest)
		return nil
	})

	if err != nil {
		return nil, err
	}

	return manifests, nil
}
```

## 6. Updated Migration Registry

Simplify the migration registry to load from YAML manifests:

```go
// migration/registry.go
package migration

import (
	"sync"
)

// Registry keeps track of all registered migrations
type Registry struct {
	migrations []Migration
	mutex      sync.RWMutex
}

// NewRegistry creates a new migration registry
func NewRegistry() *Registry {
	return &Registry{
		migrations: make([]Migration, 0),
	}
}

// Register adds a migration to the registry
func (r *Registry) Register(migration Migration) {
	r.mutex.Lock()
	defer r.mutex.Unlock()
	r.migrations = append(r.migrations, migration)
}

// GetMigrations returns all registered migrations
func (r *Registry) GetMigrations() []Migration {
	r.mutex.RLock()
	defer r.mutex.RUnlock()
	result := make([]Migration, len(r.migrations))
	copy(result, r.migrations)
	return result
}

// LoadFromManifests loads migrations from YAML manifests
func (r *Registry) LoadFromManifests(manifestDir string) error {
	manifests, err := LoadManifests(manifestDir)
	if err != nil {
		return err
	}

	for _, manifest := range manifests {
		migration, err := CreateMigration(
			manifest.Implementation,
			manifest.ID,
			manifest.Version,
			manifest.Description,
		)
		if err != nil {
			return err
		}

		r.Register(migration)
	}

	return nil
}
```

