## 8. Updated Migration Runner

The runner will now use our registry that loads from YAML:

```go
// migration/runner.go
package migration

import (
	"encoding/json"
	"os"
	"sort"
	"time"

	"github.com/Masterminds/semver/v3"
	"github.com/pkg/errors"
	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
	"gumdrop/internal/pkg/schemaMapping"
)

type MigrationRunner struct {
	registry         *Registry
	opensearchClient repository.NoSqlRepository
	schemaMapper     schemaMapping.SchemaMapper
	executedPath     string // Path to the JSON file tracking executed migrations
	manifestDir      string // Path to YAML migration manifests
}

func NewMigrationRunner(
	client repository.NoSqlRepository,
	schemaMapper schemaMapping.SchemaMapper,
	executedPath string,
	manifestDir string,
) *MigrationRunner {
	return &MigrationRunner{
		registry:         NewRegistry(),
		opensearchClient: client,
		schemaMapper:     schemaMapper,
		executedPath:     executedPath,
		manifestDir:      manifestDir,
	}
}

func (r *MigrationRunner) Run(logContext *log.Context) error {
	// Load migrations from YAML manifests
	if err := r.registry.LoadFromManifests(r.manifestDir); err != nil {
		return errors.Wrap(err, "failed to load migration manifests")
	}

	// Load executed migrations
	executed, err := r.loadExecutedMigrations()
	if err != nil {
		return errors.Wrap(err, "failed to load executed migrations")
	}

	// Get all registered migrations
	migrations := r.registry.GetMigrations()

	// Sort migrations by version
	sort.Slice(migrations, func(i, j int) bool {
		vi, _ := semver.NewVersion(migrations[i].Version())
		vj, _ := semver.NewVersion(migrations[j].Version())
		return vi.LessThan(vj)
	})

	// Execute migrations that haven't been run yet
	for _, migration := range migrations {
		id := migration.ID()
		if _, ok := executed[id]; !ok {
			log.Infow(logContext, "Executing migration", "id", id, "version", migration.Version(), "description", migration.Description())

			if err := migration.Execute(logContext, r.opensearchClient); err != nil {
				return errors.Wrapf(err, "failed to execute migration %s", id)
			}

			// Record successful migration
			executed[id] = ExecutedMigration{
				ID:          id,
				Version:     migration.Version(),
				Description: migration.Description(),
				ExecutedAt:  time.Now().UTC(),
			}

			if err := r.saveExecutedMigrations(executed); err != nil {
				return errors.Wrap(err, "failed to save executed migrations")
			}

			log.Infow(logContext, "Migration executed successfully", "id", id)
		}
	}

	return nil
}

type ExecutedMigration struct {
	ID          string    `json:"id"`
	Version     string    `json:"version"`
	Description string    `json:"description"`
	ExecutedAt  time.Time `json:"executed_at"`
}

func (r *MigrationRunner) loadExecutedMigrations() (map[string]ExecutedMigration, error) {
	executed := make(map[string]ExecutedMigration)

	if _, err := os.Stat(r.executedPath); os.IsNotExist(err) {
		return executed, nil
	}

	data, err := os.ReadFile(r.executedPath)
	if err != nil {
		return nil, err
	}

	if err := json.Unmarshal(data, &executed); err != nil {
		return nil, err
	}

	return executed, nil
}

func (r *MigrationRunner) saveExecutedMigrations(executed map[string]ExecutedMigration) error {
	data, err := json.MarshalIndent(executed, "", "  ")
	if err != nil {
		return err
	}

	return os.WriteFile(r.executedPath, data, 0644)
}
```

