## 7. Migration Runner

```go
// migration/runner.go
package migration

import (
	"encoding/json"
	"os"
	"path/filepath"

	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
	"github.com/pkg/errors"
)

// Runner executes migrations defined in the YAML config
type Runner struct {
	client      repository.NoSqlRepository
	configPath  string
	historyPath string
}

// NewRunner creates a new migration runner
func NewRunner(client repository.NoSqlRepository, configPath, historyPath string) *Runner {
	return &Runner{
		client:      client,
		configPath:  configPath,
		historyPath: historyPath,
	}
}

// Run executes all pending migrations
func (r *Runner) Run(logContext *log.Context) error {
	// Load configuration
	config, err := LoadConfig(r.configPath)
	if err != nil {
		return errors.Wrap(err, "failed to load migration config")
	}

	// Load history
	executed, err := r.loadExecutionHistory()
	if err != nil {
		return errors.Wrap(err, "failed to load migration history")
	}

	// Execute pending migrations in order
	for _, migrationDef := range config.Migrations {
		// Skip already executed migrations
		if executed[migrationDef.ID] {
			log.Infow(logContext, "Skipping already executed migration", 
				"id", migrationDef.ID, 
				"version", migrationDef.Version)
			continue
		}

		// Create migration instance
		migration, err := Create(migrationDef.Implementation)
		if err != nil {
			return errors.Wrapf(err, "failed to create migration %s", migrationDef.ID)
		}

		// Execute migration
		log.Infow(logContext, "Executing migration", 
			"id", migrationDef.ID, 
			"version", migrationDef.Version, 
			"description", migrationDef.Description)

		if err := migration.Execute(logContext, r.client); err != nil {
			return errors.Wrapf(err, "failed to execute migration %s", migrationDef.ID)
		}

		// Mark as executed
		executed[migrationDef.ID] = true
		if err := r.saveExecutionHistory(executed); err != nil {
			return errors.Wrap(err, "failed to save migration history")
		}

		log.Infow(logContext, "Migration completed successfully", "id", migrationDef.ID)
	}

	return nil
}

// loadExecutionHistory loads the already executed migrations
func (r *Runner) loadExecutionHistory() (map[string]bool, error) {
	executed := make(map[string]bool)

	// If history file doesn't exist, return empty map
	if _, err := os.Stat(r.historyPath); os.IsNotExist(err) {
		// Ensure directory exists
		dir := filepath.Dir(r.historyPath)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, err
		}
		return executed, nil
	}

	// Read and parse history file
	data, err := os.ReadFile(r.historyPath)
	if err != nil {
		return nil, err
	}

	if err := json.Unmarshal(data, &executed); err != nil {
		return nil, err
	}

	return executed, nil
}

// saveExecutionHistory saves the executed migrations
func (r *Runner) saveExecutionHistory(executed map[string]bool) error {
	data, err := json.MarshalIndent(executed, "", "  ")
	if err != nil {
		return err
	}

	return os.WriteFile(r.historyPath, data, 0644)
}
```

