func addToConfig(configPath, id, version, description, implementation string) error {
	// Read existing config
	data, err := os.ReadFile(configPath)
	if err != nil && !os.IsNotExist(err) {
		return err
	}

	// If file doesn't exist, create it
	if os.IsNotExist(err) {
		config := `migrations:
  - id: ` + id + `
    version: ` + version + `
    description: ` + description + `
    implementation: ` + implementation + `
`
		return os.WriteFile(configPath, []byte(config), 0644)
	}

	// Append to existing config
	// This is a simple implementation - in real life you might want to use yaml parsing
	config := string(data)
	if !strings.Contains(config, "migrations:") {
		config = "migrations:\n" + config
	}

	newMigration := `  - id: ` + id + `
    version: ` + version + `
    description: ` + description + `
    implementation: ` + implementation + `
`

	// Append at the end
	config = strings.TrimRight(config, "\n") + "\n" + newMigration

	return os.WriteFile(configPath, []byte(config), 0644)
}
