## 3. Enhanced Migration Runner

The runner will now compare versions to determine if a migration needs to be re-executed:

```go
// migration/runner.go
package migration

import (
	"encoding/json"
	"os"
	"path/filepath"
	"time"

	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
	"github.com/Masterminds/semver/v3"
	"github.com/pkg/errors"
)

// Runner executes migrations defined in the YAML config
type Runner struct {
	client      repository.NoSqlRepository
	configPath  string
	historyPath string
}

// NewRunner creates a new migration runner
func NewRunner(client repository.NoSqlRepository, configPath, historyPath string) *Runner {
	return &Runner{
		client:      client,
		configPath:  configPath,
		historyPath: historyPath,
	}
}

// ExecutedMigration stores information about an executed migration
type ExecutedMigration struct {
	Version string `json:"version"`
	Date    string `json:"date"`
}

// Run executes all pending migrations and re-executes migrations with version changes
func (r *Runner) Run(logContext *log.Context) error {
	// Load configuration
	config, err := LoadConfig(r.configPath)
	if err != nil {
		return errors.Wrap(err, "failed to load migration config")
	}

	// Load history
	executionHistory, err := r.loadExecutionHistory()
	if err != nil {
		return errors.Wrap(err, "failed to load migration history")
	}

	// Execute migrations in order
	for _, migrationDef := range config.Migrations {
		executed, exists := executionHistory[migrationDef.ID]
		needsExecution := true

		if exists {
			// Check if version has changed
			currentVersion, err := semver.NewVersion(migrationDef.Version)
			if err != nil {
				return errors.Wrapf(err, "invalid version for migration %s: %s", 
					migrationDef.ID, migrationDef.Version)
			}

			executedVersion, err := semver.NewVersion(executed.Version)
			if err != nil {
				// If we can't parse the previously executed version, re-execute to be safe
				log.Warnw(logContext, "Cannot parse previously executed version, will re-execute", 
					"id", migrationDef.ID, 
					"executed_version", executed.Version)
			} else if currentVersion.Equal(executedVersion) {
				// Version is the same, don't need to execute
				needsExecution = false
				log.Infow(logContext, "Skipping already executed migration", 
					"id", migrationDef.ID, 
					"version", migrationDef.Version)
			} else {
				// Version has changed, re-execute
				log.Infow(logContext, "Re-executing migration due to version change", 
					"id", migrationDef.ID, 
					"old_version", executed.Version, 
					"new_version", migrationDef.Version)
			}
		}

		if needsExecution {
			// Create migration instance
			migration, err := Create(migrationDef.Implementation)
			if err != nil {
				return errors.Wrapf(err, "failed to create migration %s", migrationDef.ID)
			}

			// Execute migration
			log.Infow(logContext, "Executing migration", 
				"id", migrationDef.ID, 
				"version", migrationDef.Version, 
				"description", migrationDef.Description)

			if err := migration.Execute(logContext, r.client); err != nil {
				return errors.Wrapf(err, "failed to execute migration %s", migrationDef.ID)
			}

			// Update execution history
			executionHistory[migrationDef.ID] = ExecutedMigration{
				Version: migrationDef.Version,
				Date:    time.Now().UTC().Format(time.RFC3339),
			}

			if err := r.saveExecutionHistory(executionHistory); err != nil {
				return errors.Wrap(err, "failed to save migration history")
			}

			log.Infow(logContext, "Migration completed successfully", "id", migrationDef.ID)
		}
	}

	return nil
}

// loadExecutionHistory loads the already executed migrations
func (r *Runner) loadExecutionHistory() (map[string]ExecutedMigration, error) {
	executed := make(map[string]ExecutedMigration)

	// If history file doesn't exist, return empty map
	if _, err := os.Stat(r.historyPath); os.IsNotExist(err) {
		// Ensure directory exists
		dir := filepath.Dir(r.historyPath)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return nil, err
		}
		return executed, nil
	}

	// Read and parse history file
	data, err := os.ReadFile(r.historyPath)
	if err != nil {
		return nil, err
	}

	if err := json.Unmarshal(data, &executed); err != nil {
		return nil, err
	}

	return executed, nil
}

// saveExecutionHistory saves the executed migrations
func (r *Runner) saveExecutionHistory(executed map[string]ExecutedMigration) error {
	data, err := json.MarshalIndent(executed, "", "  ")
	if err != nil {
		return err
	}

	return os.WriteFile(r.historyPath, data, 0644)
}
