	name        = flag.String("name", "", "Implementation name (CamelCase)")
	configPath  = flag.String("config", "migrations.yaml", "Path to migrations.yaml")
	update      = flag.Bool("update", false, "Update existing migration version")
)

const migrationTemplate = `package migrations

import (
	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/migration"
	"gumdrop/internal/pkg/repository"
	"github.com/pkg/errors"
)

// {{ .Name }} implements "{{ .Description }}"
type {{ .Name }} struct{}

func (m *{{ .Name }}) Execute(logContext *log.Context, client repository.NoSqlRepository) error {
	// TODO: Implement your migration logic here
	return nil
}
`

type MigrationConfig struct {
	Migrations []MigrationDefinition `yaml:"migrations"`
}

type MigrationDefinition struct {
	ID            string `yaml:"id"`
	Version       string `yaml:"version"`
	Description   string `yaml:"description"`
	Implementation string `yaml:"implementation"`
}

func main() {
	flag.Parse()

	if *id == "" || *version == "" {
		fmt.Println("Migration ID and version are required:")
		flag.Usage()
		os.Exit(1)
	}

	if !*update && (*description == "" || *name == "") {
		fmt.Println("Description and implementation name are required for new migrations:")
		flag.Usage()
		os.Exit(1)
	}

	// Check if the migration already exists in the config
	config, err := loadConfig(*configPath)
	if err != nil && !os.IsNotExist(err) {
		fmt.Printf("Error loading config: %v\n", err)
		os.Exit(1)
	}

	var isNewMigration = true
	if config != nil {
		for i, m := range config.Migrations {
			if m.ID == *id {
				isNewMigration = false

				if *update {
					// Update version and optionally description
					config.Migrations[i].Version = *version
					if *description != "" {
						config.Migrations[i].Description = *description
					}

					// Save updated config
					if err := saveConfig(*configPath, config); err != nil {
						fmt.Printf("Error updating config: %v\n", err)
						os.Exit(1)
					}

					fmt.Printf("Updated migration '%s' to version %s\n", *id, *version)
					return
				} else {
					fmt.Printf("Migration '%s' already exists. Use -update flag to update its version.\n", *id)
					os.Exit(1)
				}
			}
		}
	}

	if isNewMigration {
		if config == nil {
			config = &MigrationConfig{
				Migrations: []MigrationDefinition{},
			}
		}

		// 1. Add migration implementation
		implFileName := fmt.Sprintf("migrations/%s.go", strings.ToLower(*name))
		if err := createImplementation(implFileName, *name, *description); err != nil {
			fmt.Printf("Error creating implementation: %v\n", err)
			os.Exit(1)
		}

		// 2. Register migration in init.go
		if err := ensureRegistration(*name); err != nil {
			fmt.Printf("Error updating registration: %v\n", err)
			os.Exit(1)
		}

		// 3. Add to migrations.yaml
		config.Migrations = append(config.Migrations, MigrationDefinition{
			ID:            *id,
			Version:       *version,
			Description:   *description,
			Implementation: *name,
		})

		if err := saveConfig(*configPath, config); err != nil {
			fmt.Printf("Error updating config: %v\n", err)
			os.Exit(1)
		}

		fmt.Printf("Migration added successfully:\n")
		fmt.Printf("- Implementation: %s\n", implFileName)
		fmt.Printf("- Registration: migrations/init.go\n")
		fmt.Printf("- Configuration: %s\n", *configPath)
	}
}

func loadConfig(path string) (*MigrationConfig, error) {
