	}

	data := struct {
		Name        string
		Description string
	}{
		Name:        name,
		Description: description,
	}

	tmpl, err := template.New("migration").Parse(migrationTemplate)
	if err != nil {
		return err
	}

	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	return tmpl.Execute(file, data)
}

func ensureRegistration(name string) error {
	// Simple implementation - appends to init.go
	initFile := "migrations/init.go"

	// Check if file exists
	_, err := os.Stat(initFile)
	if os.IsNotExist(err) {
		// Create init.go
		content := `package migrations

import (
	"gumdrop/internal/pkg/migration"
)

func init() {
	migration.Register("` + name + `", func() migration.Migration {
		return &` + name + `{}
	})
}
`
		return os.WriteFile(initFile, []byte(content), 0644)
	}

	// Check if migration is already registered
	content, err := os.ReadFile(initFile)
	if err != nil {
		return err
	}

	if strings.Contains(string(content), "migration.Register(\""+name+"\"") {
		return nil // Already registered
	}

	// Append registration
	registration := `
	migration.Register("` + name + `", func() migration.Migration {
		return &` + name + `{}
	})
`
	file, err := os.OpenFile(initFile, os.O_APPEND|os.O_WRONLY, 0644)
	if err != nil {
		return err
	}
	defer file.Close()

	_, err = file.WriteString(registration)
	return err
}
