## 1. Smarter Migration Registry

```go
// migration/registry.go
package migration

import (
	"encoding/json"
	"os"
	"sort"
	"sync"

	"github.com/Masterminds/semver/v3"
	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
)

// MigrationInfo stores metadata about a migration
type MigrationInfo struct {
	ID          string
	Version     string
	Description string
	Execute     MigrationFunc
}

// MigrationFunc defines the function signature for migrations
type MigrationFunc func(ctx *log.Context, client repository.NoSqlRepository) error

// ExecutedMigration stores information about an executed migration
type ExecutedMigration struct {
	Version string `json:"version"`
	Date    string `json:"date"`
}

// Registry manages migration registration and execution
type Registry struct {
	migrations     map[string]MigrationInfo
	historyPath    string
	mutex          sync.RWMutex
	loadedPackages map[string]bool
}

// NewRegistry creates a migration registry
func NewRegistry(historyPath string) *Registry {
	return &Registry{
		migrations:     make(map[string]MigrationInfo),
		historyPath:    historyPath,
		loadedPackages: make(map[string]bool),
	}
}

// Register adds a migration to the registry
func (r *Registry) Register(id, version, description string, execute MigrationFunc) {
	r.mutex.Lock()
	defer r.mutex.Unlock()

	r.migrations[id] = MigrationInfo{
		ID:          id,
		Version:     version,
		Description: description,
		Execute:     execute,
	}
}

// LoadMigration dynamically loads a migration package if needed
func (r *Registry) LoadMigration(packagePath string) {
	r.mutex.Lock()
	defer r.mutex.Unlock()

	if !r.loadedPackages[packagePath] {
		// This will trigger the init() function in the package
		// which will call Register for the migrations in that package
		// We're using a closure to avoid import cycles
		loader := func(path string) {
			// The Go runtime will execute the init() function in the package,
			// which will register the migration via Registry.Register()
			// This is a placeholder for dynamic loading
		}

		loader(packagePath)
		r.loadedPackages[packagePath] = true
	}
}

// GetPendingMigrations returns migrations that need to be executed
func (r *Registry) GetPendingMigrations(logContext *log.Context) ([]MigrationInfo, error) {
	// Load execution history
	executionHistory, err := r.loadExecutionHistory()
	if err != nil {
		return nil, err
	}

	// Find migrations that need execution
	var pendingMigrations []MigrationInfo

	r.mutex.RLock()
	defer r.mutex.RUnlock()

	for id, migration := range r.migrations {
		executed, exists := executionHistory[id]
		needsExecution := true

		if exists {
			// Check if version has changed
			currentVersion, err := semver.NewVersion(migration.Version)
			if err != nil {
				return nil, err
			}

			executedVersion, err := semver.NewVersion(executed.Version)
			if err != nil {
				// If we can't parse the previously executed version, re-execute to be safe
				needsExecution = true
			} else if currentVersion.Equal(executedVersion) {
				// Version is the same, don't need to execute
				needsExecution = false
			}
		}

		if needsExecution {
			pendingMigrations = append(pendingMigrations, migration)
		}
	}

	// Sort pending migrations by version
	sort.Slice(pendingMigrations, func(i, j int) bool {
		vi, _ := semver.NewVersion(pendingMigrations[i].Version)
		vj, _ := semver.NewVersion(pendingMigrations[j].Version)
		return vi.LessThan(vj)
	})

	return pendingMigrations, nil
}

// UpdateExecutionHistory records a successful migration
func (r *Registry) UpdateExecutionHistory(id, version string) error {
	// Load execution history
	executionHistory, err := r.loadExecutionHistory()
	if err != nil {
		return err
	}

	// Update history
	executionHistory[id] = ExecutedMigration{
		Version: version,
		Date:    time.Now().UTC().Format(time.RFC3339),
	}

	// Save updated history
	return r.saveExecutionHistory(executionHistory)
}

// loadExecutionHistory loads the already executed migrations
func (r *Registry) loadExecutionHistory() (map[string]ExecutedMigration, error) {
	executed := make(map[string]ExecutedMigration)

	// If history file doesn't exist, return empty map
	if _, err := os.Stat(r.historyPath); os.IsNotExist(err) {
		return executed, nil
	}

	// Read and parse history file
	data, err := os.ReadFile(r.historyPath)
	if err != nil {
		return nil, err
	}

	if err := json.Unmarshal(data, &executed); err != nil {
		return nil, err
	}

	return executed, nil
}

// saveExecutionHistory saves the executed migrations
func (r *Registry) saveExecutionHistory(executed map[string]ExecutedMigration) error {
	data, err := json.MarshalIndent(executed, "", "  ")
	if err != nil {
		return err
	}

	// Ensure directory exists
	dir := filepath.Dir(r.historyPath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	return os.WriteFile(r.historyPath, data, 0644)
}
