```go
// migration/runner.go
package migration

import (
	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
	"github.com/pkg/errors"
)

// Runner executes pending migrations
type Runner struct {
	registry  *Registry
	client    repository.NoSqlRepository
	allMigIDs []string  // Optional: list of all known migration IDs (for pre-checking)
}

// NewRunner creates a new migration runner
func NewRunner(
	historyPath string,
	client repository.NoSqlRepository,
	allMigrationIDs []string,
) *Runner {
	return &Runner{
		registry:  NewRegistry(historyPath),
		client:    client,
		allMigIDs: allMigrationIDs,
	}
}

// getRequiredMigrationIDs finds migrations that need to be loaded
func (r *Runner) getRequiredMigrationIDs(logContext *log.Context) ([]string, error) {
	// Load execution history
	executionHistory, err := r.registry.loadExecutionHistory()
	if err != nil {
		return nil, errors.Wrap(err, "failed to load migration history")
	}

	var requiredIDs []string

	// Check which migrations need to be loaded
	for _, id := range r.allMigIDs {
		executed, exists := executionHistory[id]
		if !exists {
			// Never executed, definitely need to load
			requiredIDs = append(requiredIDs, id)
			continue
		}

		// If we know the current version, we can check if it's changed
		if currentVersion, ok := KnownMigrationVersions[id]; ok {
			if currentVersion != executed.Version {
				// Version changed, need to load
				requiredIDs = append(requiredIDs, id)
			}
		} else {
			// Don't know the current version, load to be safe
			requiredIDs = append(requiredIDs, id)
		}
	}

	return requiredIDs, nil
}

// Run executes pending migrations
func (r *Runner) Run(logContext *log.Context) error {
	// Optionally pre-check which migrations need to be loaded
	if len(r.allMigIDs) > 0 {
		requiredIDs, err := r.getRequiredMigrationIDs(logContext)
		if err != nil {
			return err
		}

		// Load only required migrations
		for _, id := range requiredIDs {
			if packagePath, ok := MigrationPackageMap[id]; ok {
				r.registry.LoadMigration(packagePath)
			}
		}
	}

	// Get pending migrations
	pendingMigrations, err := r.registry.GetPendingMigrations(logContext)
	if err != nil {
		return errors.Wrap(err, "failed to get pending migrations")
	}

	// Execute pending migrations
	for _, migration := range pendingMigrations {
		log.Infow(logContext, "Executing migration", 
			"id", migration.ID, 
			"version", migration.Version, 
			"description", migration.Description)

		// Execute the migration
		if err := migration.Execute(logContext, r.client); err != nil {
			return errors.Wrapf(err, "failed to execute migration %s", migration.ID)
		}

		// Update execution history
		if err := r.registry.UpdateExecutionHistory(migration.ID, migration.Version); err != nil {
			return errors.Wrapf(err, "failed to update execution history for %s", migration.ID)
		}

		log.Infow(logContext, "Migration completed successfully", "id", migration.ID)
	}

	return nil
}
```

