# Ultra-Simple Migration Framework with Execution Skipping

Let's simplify this to the bare minimum. We'll create a migration framework that reads the list of executed migrations and only registers those that haven't been executed yet.

## 1. Simple Migration Interface and Registry

```go
// migration/migration.go
package migration

import (
	"encoding/json"
	"os"
	"sync"

	"gumdrop/internal/pkg/log"
	"gumdrop/internal/pkg/repository"
)

// Migration function type
type MigrationFunc func(ctx *log.Context, client repository.NoSqlRepository) error

// Registry for migrations
var (
	migrations = make(map[string]struct {
		Version     string
		Description string
		Execute     MigrationFunc
	})
	mutex sync.RWMutex

	// Track which migrations have already been registered
	registered = make(map[string]bool)
)

// ExecutedMigration represents a migration that has been run
type ExecutedMigration struct {
	Version string `json:"version"`
}

// LoadExecutedMigrations reads the list of already executed migrations
func LoadExecutedMigrations(filePath string) (map[string]ExecutedMigration, error) {
	executed := make(map[string]ExecutedMigration)

	// If file doesn't exist, return empty map
	if _, err := os.Stat(filePath); os.IsNotExist(err) {
		return executed, nil
	}

	data, err := os.ReadFile(filePath)
	if err != nil {
		return nil, err
	}

	if err := json.Unmarshal(data, &executed); err != nil {
		return nil, err
	}

	return executed, nil
}

// Register adds a migration to the registry if it hasn't been executed
// or if its version has changed
func Register(id, version, description string, executedList map[string]ExecutedMigration, execute MigrationFunc) {
	// Skip if already registered
	if registered[id] {
		return
	}

	// Check if already executed with same version
	if executed, ok := executedList[id]; ok && executed.Version == version {
		// Already executed with same version, don't register
		registered[id] = true
		return
	}

	// Register the migration
	mutex.Lock()
	migrations[id] = struct {
		Version     string
		Description string
		Execute     MigrationFunc
	}{
		Version:     version,
		Description: description,
		Execute:     execute,
	}
	registered[id] = true
	mutex.Unlock()
}

// GetMigrations returns all registered migrations
func GetMigrations() map[string]struct {
	Version     string
	Description string
	Execute     MigrationFunc
} {
	mutex.RLock()
	defer mutex.RUnlock()

	// Make a copy to avoid race conditions
	result := make(map[string]struct {
		Version     string
		Description string
		Execute     MigrationFunc
	})

	for id, migration := range migrations {
		result[id] = migration
	}

	return result
}
