	}

	// Get all registered migrations (only those not already executed)
	migrations := GetMigrations()

	// Sort migration IDs by version (for consistent execution order)
	var migrationIDs []string
	for id := range migrations {
		migrationIDs = append(migrationIDs, id)
	}

	sort.Strings(migrationIDs)

	// Execute migrations
	for _, id := range migrationIDs {
		migration := migrations[id]

		log.Infow(logContext, "Executing migration", 
			"id", id, 
			"version", migration.Version, 
			"description", migration.Description)

		// Execute the migration
		if err := migration.Execute(logContext, client); err != nil {
			return errors.Wrapf(err, "failed to execute migration %s", id)
		}

		// Update execution history
		executed[id] = ExecutedMigration{Version: migration.Version}

		// Save updated history
		data, err := json.MarshalIndent(executed, "", "  ")
		if err != nil {
			return errors.Wrap(err, "failed to marshal execution history")
		}

		if err := os.WriteFile(historyPath, data, 0644); err != nil {
			return errors.Wrap(err, "failed to save execution history")
		}

		log.Infow(logContext, "Migration completed successfully", "id", id)
	}

	return nil
}
